/*
 * montty.c — MonTTY Terminal Device Driver
 *
 * Mesa-style monitor with one mutex shared across all NUM_TERMINALS terminals.
 *
 * Entry procedures (all call Declare_Monitor_Entry_Procedure):
 *   ReceiveInterrupt, TransmitInterrupt          (bottom half)
 *   WriteTerminal, ReadTerminal, InitTerminal,
 *   TerminalDriverStatistics, InitTerminalDriver (top half)
 *
 * All helper functions are static (not entry procedures).
 */

#include <stddef.h>
#include <threads.h>
#include <hardware.h>
#include <terminals.h>

/* Fallback if system header doesn't define TERMINAL_MAX_LINE */
#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 1024
#endif

/*
 * Buffer sizes.  COMP_BUF_SIZE must be large enough to hold several
 * complete lines so that ReadTerminal callers that are slow to consume
 * do not cause data loss.  ECHO_BUF_SIZE must be large enough to hold
 * the burst of echo characters generated by rapid typing (worst case:
 * 3 chars per keystroke for backspace).
 */
#define COMP_BUF_SIZE 16384
#define ECHO_BUF_SIZE  1024

/* Per-terminal state */
struct tty_state {
    int initialized;

    /* Current (incomplete) line being typed — not yet in comp_buf */
    char  cur_line[TERMINAL_MAX_LINE];
    int   cur_line_len;

    /* Completed lines waiting for ReadTerminal — circular buffer */
    char  comp_buf[COMP_BUF_SIZE];
    int   comp_head;
    int   comp_tail;
    int   comp_count;   /* total bytes in comp_buf */
    int   line_count;   /* number of '\n' chars in comp_buf */

    /* Echo characters to send — circular buffer, echo has priority */
    char  echo_buf[ECHO_BUF_SIZE];
    int   echo_head;
    int   echo_tail;
    int   echo_count;

    /* Transmit hardware state */
    int   transmit_busy;  /* 1 while a char is being sent to hardware */

    /* WriteTerminal serialization and state */
    int   write_busy;     /* 1 while a WriteTerminal call is active */
    int   write_pending;  /* 1 while a writer is waiting to send or finishing */

    /* Statistics */
    struct termstat stats;

    /* Condition variables */
    cond_id_t read_cv;        /* ReadTerminal waits here for a complete line */
    cond_id_t write_cv;       /* WriteTerminal waits here for transmit + no echo */
    cond_id_t write_lock_cv;  /* serializes concurrent WriteTerminal callers */
};

static struct tty_state ttys[NUM_TERMINALS];
static int driver_initialized = 0;

/* ------------------------------------------------------------------ */
/* Internal (non-entry) helpers                                        */
/* ------------------------------------------------------------------ */

static void echo_push(int term, char c)
{
    if (ttys[term].echo_count < ECHO_BUF_SIZE) {
        ttys[term].echo_buf[ttys[term].echo_tail] = c;
        ttys[term].echo_tail = (ttys[term].echo_tail + 1) % ECHO_BUF_SIZE;
        ttys[term].echo_count++;
    }
}

static char echo_pop(int term)
{
    char c = ttys[term].echo_buf[ttys[term].echo_head];
    ttys[term].echo_head = (ttys[term].echo_head + 1) % ECHO_BUF_SIZE;
    ttys[term].echo_count--;
    return c;
}

static void comp_push(int term, char c)
{
    if (ttys[term].comp_count < COMP_BUF_SIZE) {
        ttys[term].comp_buf[ttys[term].comp_tail] = c;
        ttys[term].comp_tail = (ttys[term].comp_tail + 1) % COMP_BUF_SIZE;
        ttys[term].comp_count++;
    }
}

static char comp_pop(int term)
{
    char c = ttys[term].comp_buf[ttys[term].comp_head];
    ttys[term].comp_head = (ttys[term].comp_head + 1) % COMP_BUF_SIZE;
    ttys[term].comp_count--;
    return c;
}

/*
 * start_transmit — send the next pending character (if any).
 *
 * Called with the monitor held and transmit_busy already cleared (or
 * when we know it is 0).  Echo has priority over WriteTerminal output.
 */
static void start_transmit(int term)
{
    if (ttys[term].transmit_busy)
        return;

    if (ttys[term].echo_count > 0) {
        char c = echo_pop(term);
        WriteDataRegister(term, c);
        ttys[term].transmit_busy = 1;
        ttys[term].stats.tty_out++;
    } else if (ttys[term].write_pending) {
        /* Wake the writer so it can send its next character */
        CondSignal(ttys[term].write_cv);
    }
}

/* ------------------------------------------------------------------ */
/* Entry procedures                                                    */
/* ------------------------------------------------------------------ */

int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    if (driver_initialized)
        return -1;

    int i;
    for (i = 0; i < NUM_TERMINALS; i++) {
        ttys[i].initialized    = 0;
        ttys[i].cur_line_len   = 0;
        ttys[i].comp_head      = 0;
        ttys[i].comp_tail      = 0;
        ttys[i].comp_count     = 0;
        ttys[i].line_count     = 0;
        ttys[i].echo_head      = 0;
        ttys[i].echo_tail      = 0;
        ttys[i].echo_count     = 0;
        ttys[i].transmit_busy  = 0;
        ttys[i].write_busy     = 0;
        ttys[i].write_pending  = 0;
        ttys[i].stats.tty_in   = -1;
        ttys[i].stats.tty_out  = -1;
        ttys[i].stats.user_in  = -1;
        ttys[i].stats.user_out = -1;
        ttys[i].read_cv        = CondCreate();
        ttys[i].write_cv       = CondCreate();
        ttys[i].write_lock_cv  = CondCreate();
    }

    driver_initialized = 1;
    return 0;
}

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)            return -1;
    if (term < 0 || term >= NUM_TERMINALS) return -1;
    if (ttys[term].initialized)        return -1;

    if (InitHardware(term) == -1)
        return -1;

    ttys[term].initialized    = 1;
    ttys[term].stats.tty_in   = 0;
    ttys[term].stats.tty_out  = 0;
    ttys[term].stats.user_in  = 0;
    ttys[term].stats.user_out = 0;
    return 0;
}

/*
 * ReceiveInterrupt — bottom half, keyboard input.
 *
 * MUST NOT call CondWait (must not block).
 */
void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    char c = ReadDataRegister(term);
    ttys[term].stats.tty_in++;

    struct tty_state *t = &ttys[term];

    if (c == '\r' || c == '\n') {
        /* Echo \r\n */
        echo_push(term, '\r');
        echo_push(term, '\n');

        /* Move current line + '\n' into the completed buffer */
        int i;
        for (i = 0; i < t->cur_line_len; i++)
            comp_push(term, t->cur_line[i]);
        comp_push(term, '\n');
        t->line_count++;
        t->cur_line_len = 0;

        /* Wake a waiting ReadTerminal caller */
        CondSignal(t->read_cv);

    } else if (c == '\b' || c == '\177') {
        /* Backspace / delete */
        if (t->cur_line_len > 0) {
            t->cur_line_len--;
            echo_push(term, '\b');
            echo_push(term, ' ');
            echo_push(term, '\b');
        }
        /* If buffer empty, do nothing */

    } else {
        /* Ordinary character */
        if (t->cur_line_len < TERMINAL_MAX_LINE) {
            t->cur_line[t->cur_line_len++] = c;
            echo_push(term, c);
        }
        /* Buffer full: drop character (could optionally ring bell) */
    }

    start_transmit(term);
}

/*
 * TransmitInterrupt — bottom half, transmit complete.
 */
void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    ttys[term].transmit_busy = 0;
    start_transmit(term);
}

/*
 * WriteTerminal — top half, write buflen chars to terminal term.
 *
 * '\n' is expanded to '\r\n' on output.
 * Serializes concurrent writers; echo always has priority.
 * Returns buflen on success, -1 on error.
 */
int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)               return -1;
    if (term < 0 || term >= NUM_TERMINALS) return -1;
    if (!ttys[term].initialized)           return -1;
    if (buf == NULL)                       return -1;
    if (buflen < 0)                        return -1;
    if (buflen == 0)                       return 0;

    struct tty_state *t = &ttys[term];

    /* Account for user_in before serializing (spec says on call) */
    t->stats.user_in += buflen;

    /* Serialize: wait until no other WriteTerminal is active */
    while (t->write_busy)
        CondWait(t->write_lock_cv);
    t->write_busy    = 1;
    t->write_pending = 1;

    int i;
    for (i = 0; i < buflen; i++) {
        char c = buf[i];

        if (c == '\n') {
            /* Output '\n' as '\r' + '\n' */
            while (t->transmit_busy || t->echo_count > 0)
                CondWait(t->write_cv);
            WriteDataRegister(term, '\r');
            t->transmit_busy = 1;
            t->stats.tty_out++;

            while (t->transmit_busy || t->echo_count > 0)
                CondWait(t->write_cv);
            WriteDataRegister(term, '\n');
            t->transmit_busy = 1;
            t->stats.tty_out++;
        } else {
            while (t->transmit_busy || t->echo_count > 0)
                CondWait(t->write_cv);
            WriteDataRegister(term, c);
            t->transmit_busy = 1;
            t->stats.tty_out++;
        }
    }

    /* Wait for the last character to finish transmitting */
    while (t->transmit_busy)
        CondWait(t->write_cv);

    t->write_pending = 0;
    t->write_busy    = 0;
    CondSignal(t->write_lock_cv);

    return buflen;
}

/*
 * ReadTerminal — top half, read next line from terminal term into buf.
 *
 * Blocks until a complete line ('\n') is available.  Returns up to
 * buflen characters, stopping after (and including) the first '\n'.
 * Remaining characters of the line stay in the buffer for the next call.
 * Returns number of chars placed in buf, or -1 on error.
 */
int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)               return -1;
    if (term < 0 || term >= NUM_TERMINALS) return -1;
    if (!ttys[term].initialized)           return -1;
    if (buf == NULL)                       return -1;
    if (buflen < 0)                        return -1;
    if (buflen == 0)                       return 0;

    struct tty_state *t = &ttys[term];

    /* Block until at least one complete line is in comp_buf */
    while (t->line_count == 0)
        CondWait(t->read_cv);

    /* Copy up to buflen chars, stopping after the first '\n' */
    int count = 0;
    while (count < buflen && t->comp_count > 0) {
        char c = comp_pop(term);
        buf[count++] = c;
        if (c == '\n') {
            t->line_count--;
            break;
        }
    }

    t->stats.user_out += count;
    return count;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized) return -1;
    if (stats == NULL)       return -1;

    int i;
    for (i = 0; i < NUM_TERMINALS; i++)
        stats[i] = ttys[i].stats;

    return 0;
}

